VALUES
  ('judicial-57f41407-moex-00143', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於「簡易判決處刑」之聲請，下列敘述何者錯誤？', '["須經檢察官審酌案件情節，認為宜以簡易判決處刑者", "被告於偵查中自白者，得請求檢察官聲請簡易判決處刑", "以宣告緩刑、得易科罰金或得易服社會勞動之有期徒刑及拘役或罰金為限", "檢察官為簡易判決處刑之聲請者，與緩起訴有相同之效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00144', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何種罪名之案件，經第二審判決後，可以上訴至最高法院？', '["刑法第339條詐欺罪", "刑法第302條妨害自由罪", "刑法第277條第1項傷害罪", "刑法第346條恐嚇罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00145', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於非常上訴、再審之敘述，下列何者錯誤？', '["非常上訴與再審，都是針對確定裁判之救濟方法，區別在於非常上訴是針對裁判違背法令，再審是 針對判決事實錯誤", "被告在監，法院審理期日之傳票僅送達其住所，即不待其到庭逕行判決，判決確定後，應以非常上 訴之方式救濟", "非常上訴與再審，均得由受判決人提起", "非常上訴之提起，不論裁判確定後經過多久，均得為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00146', 'judicial-57f41407', 'judicial-57f41407-moex-114-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '下列何項法律規定，涉及法律施行之「地的效力」？', '["民法第314條規定，以給付特定物為標的者，以其物於訂約時之所在地為清償地", "民事訴訟法第1條規定，訴訟，由被告住所地之法院管轄", "憲法第52條規定，總統除犯內亂或外患罪外，非經罷免或解職，不受刑事上之訴究", "刑法第5條規定，在中華民國領域外犯外患罪者，適用中華民國刑法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "1b9e537fe27e", "answer_pdf_sha1": "ad1eaf69a973", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
